public object FfiConverterTypeBpeTokenizer: FfiConverter<BpeTokenizer, Pointer> {

    override fun lower(value: BpeTokenizer): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): BpeTokenizer {
        return BpeTokenizer(value)
    }

    override fun read(buf: ByteBuffer): BpeTokenizer {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: BpeTokenizer) = 8UL

    override fun write(value: BpeTokenizer, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}


