sealed class NarrationGrouping {
    
    object Sentence : NarrationGrouping()
    
    
    data class Paragraph(
        val `targetCharacters`: kotlin.UInt) : NarrationGrouping() {
        companion object
    }
    

    
    companion object
}

public object FfiConverterTypeNarrationGrouping : FfiConverterRustBuffer<NarrationGrouping>{
    override fun read(buf: ByteBuffer): NarrationGrouping {
        return when(buf.getInt()) {
            1 -> NarrationGrouping.Sentence
            2 -> NarrationGrouping.Paragraph(
                FfiConverterUInt.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: NarrationGrouping) = when(value) {
        is NarrationGrouping.Sentence -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is NarrationGrouping.Paragraph -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`targetCharacters`)
            )
        }
    }

    override fun write(value: NarrationGrouping, buf: ByteBuffer) {
        when(value) {
            is NarrationGrouping.Sentence -> {
                buf.putInt(1)
                Unit
            }
            is NarrationGrouping.Paragraph -> {
                buf.putInt(2)
                FfiConverterUInt.write(value.`targetCharacters`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}







